     5→export type ErrorLike = {
     6→  message: string;
     7→  stack: string;
     8→};
     9→
    10→export function isErrorLike(value: any): value is ErrorLike {
    11→  return Boolean(
    12→    typeof value?.message === 'string' && typeof value?.stack === 'string',
    13→  );
    14→}
    15→
    16→export function assertErrorLike(value: unknown): asserts value is ErrorLike {
    17→  if (!isErrorLike(value)) {
    18→    throw value;
    19→  }
    20→}
