    22→let IS_NOT_PRODUCTION =
    23→  typeof process === 'object' && process.env?.NODE_ENV !== 'production';
    24→
    25→export type InvariantMessage =
    26→  | string
    27→  | ((typeName: string) => string)
    28→  | {
    29→      message?: string;
    30→      stack?: string;
    31→    };
    32→
    33→export function parseInvariantMessage(
    34→  errorOrMessage: InvariantMessage | undefined,
    35→  value: unknown,
    36→) {
    37→  if (typeof errorOrMessage === 'string') return errorOrMessage;
    38→  if (
    39→    errorOrMessage &&
    40→    typeof errorOrMessage === 'object' &&
    41→    typeof errorOrMessage.message == 'string'
    42→  ) {
    43→    return errorOrMessage.message;
    44→  }
    45→  if (typeof errorOrMessage === 'function') {
    46→    return errorOrMessage(getTypeOf(value));
    47→  }
    48→  return `Expected value to be defined.`;
    49→}
    50→
    51→/**
    52→ * Custom error used by the invariant() helper;
    53→ */
    54→export class InvariantError extends Error {
    55→  static logSensitiveData = IS_NOT_PRODUCTION;
    56→
    57→  constructor(
    58→    /**
    59→     * Error information
    60→     */
    61→    message: InvariantMessage,
    62→    /**
    63→     * Function to move stack trace to.
    64→     */
    65→    customStackTraceParentFn: Function,
    66→    /**
    67→     *  will be logged withing the error if InvariantError.isNotProduction === true
    68→     */
    69→    extraInfo: any = EMPTY,
    70→  ) {
    71→    const textMessage = parseInvariantMessage(
    72→      message,
    73→      extraInfo === EMPTY ? undefined : extraInfo,
    74→    );
    75→
    76→    super(textMessage);
    77→
    78→    if (typeof message === 'object' && 'stack' in message) {
    79→      this.stack = message.stack;
    80→    }
