    82→    if (customStackTraceParentFn) {
    83→      Error.captureStackTrace?.(this, customStackTraceParentFn);
    84→    }
    85→
    86→    if (extraInfo !== EMPTY && InvariantError.logSensitiveData) {
    87→      console.trace(message, `\n‣ Error info: `, extraInfo);
    88→    }
    89→  }
    90→}
    91→
    92→/**
    93→ * Asserts against 'falsy' values
    94→ * @param value
    95→ * @param message
    96→ * @param customStackTraceParentFn
    97→ */
    98→export function invariant(
    99→  value: unknown,
   100→  message:
   101→    | string
   102→    | ((typeName: string) => string) = 'Expected value not to be falsy.',
   103→  customStackTraceParentFn?: Function,
   104→): asserts value {
   105→  if (!value) {
   106→    throw new InvariantError(
   107→      typeof message === 'string' ? message : message(getTypeOf(value)),
   108→      customStackTraceParentFn ?? invariant,
   109→    );
   110→  }
   111→}
   112→
   113→export function tryCatch<T>(
   114→  handler: () => T,
   115→  parentStack?: Function,
   116→): readonly [Error, never] | readonly [never, T] {
   117→  try {
   118→    const result: [Error | undefined, T | undefined] = [
